# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor._

case class Deposit(amount: Double)
case class Withdraw(amount: Double)
case object GetBalance

class AccountActor extends Actor {
  var balance: Double = 0.0

  def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! s"Deposited: $amount"
    case Withdraw(amount) =>
      if (balance >= amount) {
        balance -= amount
        sender() ! s"Withdrew: $amount"
      } else {
        sender() ! s"Insufficient funds for withdrawal of: $amount"
      }
    case GetBalance =>
      sender() ! s"Current balance: $balance"
  }
}

object AccountActorApp extends App {
  val system = ActorSystem("AccountActorSystem")
  val accountActor = system.actorOf(Props[AccountActor], "accountActor")

  // Example usage
  accountActor ! Deposit(1000)
  accountActor ! Withdraw(500)
  accountActor ! GetBalance
}